# Global counter for cycling through images per category
_img_counters: dict[str, int] = {}

def p(name, desc, price, cat, stock, rating=None, reviews=None):
    """Create a product document with a real product image from CDN."""
    # Get the image pool for this category
    pool = CATEGORY_IMAGES.get(cat, CATEGORY_IMAGES["Electronics"])

    # Cycle through images
    idx = _img_counters.get(cat, 0)
    _img_counters[cat] = idx + 1
    image_url = pool[idx % len(pool)]

    return {
        "name": name,
        "description": desc,
        "price": round(price, 2),
        "category": cat,
        "stock": stock,
        "images": [image_url],
        "average_rating": rating or round(random.uniform(3.8, 5.0), 1),
        "review_count": reviews or random.randint(10, 2500),
        "created_at": rand_date(),
    }

