async def seed():
    client = AsyncIOMotorClient(MONGODB_URI)
    db = client[DB_NAME]

    print("Clearing existing products...")
    await db.products.delete_many({})

    print(f"Inserting {len(PRODUCTS)} products...")
    await db.products.insert_many(PRODUCTS)

    print("Dropping existing text indexes if any...")
    try:
        indexes = await db.products.list_indexes().to_list(None)
        for idx in indexes:
            if "_fts" in idx["key"]:
                await db.products.drop_index(idx["name"])
    except Exception as e:
        print(f"No index to drop: {e}")

    print("Creating text index for search...")
    await db.products.create_index([("name", "text"), ("description", "text"), ("category", "text")])

    print(f"Seed complete! Total products: {len(PRODUCTS)}")
    client.close()

if __name__ == "__main__":
    asyncio.run(seed())

